package ir.tahamohamadi.persistence;
import org.flywaydb.core.Flyway; import org.junit.jupiter.api.Test; import org.testcontainers.containers.PostgreSQLContainer; import org.testcontainers.junit.jupiter.*; import static org.assertj.core.api.Assertions.assertThat;
@Testcontainers class FlywayWaveBIntegrationTest { @Container static final PostgreSQLContainer<?> POSTGRES=new PostgreSQLContainer<>("postgres:17-alpine"); @Test void migratesFreshDatabaseThroughWaveB(){ Flyway flyway=Flyway.configure().dataSource(POSTGRES.getJdbcUrl(),POSTGRES.getUsername(),POSTGRES.getPassword()).locations("classpath:db/migration").load(); assertThat(flyway.migrate().targetSchemaVersion).isEqualTo("7"); assertThat(flyway.migrate().migrationsExecuted).isZero(); } }
